spec.setup_code:
var dir = new api.THREE.Vector3(1, 0, 0);
                var origin = new api.THREE.Vector3(0, 0, 0);
                var arrow = new api.THREE.ArrowHelper(dir, origin, 1.4, 0xE8593C, 0.35, 0.2);
                api.group.add(arrow);
                return {
                  update: function(t) {
                    var angle = t * 0.015;
                    var newDir = new api.THREE.Vector3(Math.cos(angle), Math.sin(angle * 0.6), Math.sin(angle));
                    newDir.normalize();
                    arrow.setDirection(newDir);
                  }
                };

return {
          draw: function(ctx, W, H, t, dt) {
            ctx.fillStyle = '#F5F0E8';
            ctx.fillRect(0, 0, W, H);

            var speed = 40 + 20 * Math.sin(t * 0.03);

            ctx.fillStyle = '#333';
            ctx.font = 'bold 13px Arial';
            ctx.fillText('Scalar: speed (just a number)', 20, 25);
            ctx.font = 'bold 22px Arial';
            ctx.fillStyle = '#DC2626';
            ctx.fillText(speed.toFixed(0) + ' km/h', 30, H / 2);

            ctx.fillStyle = '#333';
            ctx.font = 'bold 13px Arial';
            ctx.fillText('Vector: velocity (number + direction)', W / 2 + 10, 25);

            var cx = W / 2 + 110;
            var cy = H / 2 + 10;
            var angle = t * 0.02;
            var len = 50;
            ctx.strokeStyle = '#3B82F6';
            ctx.lineWidth = 3;
            ctx.beginPath();
            ctx.moveTo(cx, cy);
            ctx.lineTo(cx + Math.cos(angle) * len, cy + Math.sin(angle) * len);
            ctx.stroke();

            var tipX = cx + Math.cos(angle) * len;
            var tipY = cy + Math.sin(angle) * len;
            ctx.beginPath();
            ctx.moveTo(tipX, tipY);
            ctx.lineTo(tipX - 10 * Math.cos(angle - 0.4), tipY - 10 * Math.sin(angle - 0.4));
            ctx.lineTo(tipX - 10 * Math.cos(angle + 0.4), tipY - 10 * Math.sin(angle + 0.4));
            ctx.closePath();
            ctx.fillStyle = '#3B82F6';
            ctx.fill();
          }
        };

return {
          draw: function(ctx, w, h) {
            ctx.clearRect(0, 0, w, h);
            ctx.fillStyle = '#F5F0E8';
            ctx.fillRect(0, 0, w, h);

            var mag = (state.magnitude !== undefined) ? state.magnitude : 40;
            var angleDeg = (state.angle !== undefined) ? state.angle : 45;
            var angleRad = angleDeg * Math.PI / 180;

            var cx = w / 2;
            var cy = h / 2;
            var pxLen = 30 + mag * 1.2;

            ctx.strokeStyle = '#E5E7EB';
            ctx.lineWidth = 1;
            ctx.beginPath();
            ctx.moveTo(0, cy);
            ctx.lineTo(w, cy);
            ctx.moveTo(cx, 0);
            ctx.lineTo(cx, h);
            ctx.stroke();

            var tipX = cx + Math.cos(angleRad) * pxLen;
            var tipY = cy - Math.sin(angleRad) * pxLen;

            ctx.strokeStyle = '#3B82F6';
            ctx.lineWidth = 3;
            ctx.beginPath();
            ctx.moveTo(cx, cy);
            ctx.lineTo(tipX, tipY);
            ctx.stroke();

            ctx.fillStyle = '#3B82F6';
            ctx.beginPath();
            ctx.moveTo(tipX, tipY);
            ctx.lineTo(tipX - 12 * Math.cos(angleRad - 0.4), tipY + 12 * Math.sin(angleRad - 0.4));
            ctx.lineTo(tipX - 12 * Math.cos(angleRad + 0.4), tipY + 12 * Math.sin(angleRad + 0.4));
            ctx.closePath();
            ctx.fill();

            ctx.fillStyle = '#111827';
            ctx.font = 'bold 13px Arial';
            ctx.fillText('Vector: ' + mag.toFixed(0) + ' m/s at ' + angleDeg.toFixed(0) + ' degrees', 12, 22);
          },
          onControlChange: function(id, val) {
            state[id] = val;
          },
          init: function() {
            state.magnitude = 40;
            state.angle = 45;
          }
        };
